var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_QM","text":{"KOREA":"으음…… 눈 부셔…….","JPN":"ううん……眩しい……","ENG":"Mmm... It’s too bright...","TWN":"唔……好刺眼……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_QM","text":{"KOREA":"여긴……?","JPN":"ここは……？","ENG":"Where am I...?","TWN":"這裡是……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MOM_NPC_GAMECIRCLE_NULL","text":{"KOREA":"처, 철수야……? 김철수!?","JPN":"じ、ジロウ……？　ジロウ！？","ENG":"C-Chulsoo...? Chulsoo!","TWN":"哲…哲洙……？金哲洙！？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"엄마?","JPN":"お母さん？","ENG":"Mom?","TWN":"媽！？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MOM_NPC_GAMECIRCLE_NULL","text":{"KOREA":"흑, 흐윽. 다행이다. 다행이야 철수야……!","JPN":"うっ、ううっ。よかった。よかったよ、ジロウ……！","ENG":"*Sniffle...* *Sob* Thank goodness you’re back... Chulsoo!","TWN":"嗚嗚，沒事就好，你沒事就好……！"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"엄마……? 뭐야……? 왜 울어……?","JPN":"お母さん……？　何……？　なんで泣いてるの……？","ENG":"Mom...? What’s wrong..? Why are you crying...?","TWN":"媽……？發生什麼事……？你幹嘛哭……？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MOM_NPC_GAMECIRCLE_NULL","text":{"KOREA":"왜 우냐니!? 그걸 몰라서 묻니? 학교도 안 나가고…… 밖에서는 이상한 가면만 쓰고 다니고!","JPN":"なんでって！！　当たり前でしょう！　学校にも出ないで……外では変なお面ばっかり被って！","ENG":"You know perfectly well, little mister! You refused to go to school... then started wearing some strange mask!","TWN":"什麼為什麼？你還敢問我！？你沒去上學……戴著奇怪的面具在外面亂晃！"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MOM_NPC_GAMECIRCLE_NULL","text":{"KOREA":"게다가 엄마 몰래 <color=#ffd34c>그런 곳</color>에 갔다가 다치기까지 했는데 엄마가 안 울게 생겼어!?","JPN":"しかも、お母さんに内緒で<color=#ffd34c>あんなところ</color>に行って怪我までして、そりゃあ泣くわよ！！","ENG":"Not only that, you got into trouble at a place like <color=#ffd34c>that</color>... How could I not cry?","TWN":"瞞著媽媽去<color=#ffd34c>那種地方</color>，結果還受傷，媽媽能不哭媽！？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MOM_NPC_GAMECIRCLE_NULL","text":{"KOREA":"왜 그렇게…… 왜 그렇게 엄마 속을 썩이는 거니…… 진짜. 흐윽!","JPN":"どうして……どうしてお母さんを悲しませるの……まったく。ううっ！","ENG":"Why... why are you making things so hard for me, Chulsoo...? Really... *Sob*","TWN":"你這孩子……為什麼要害媽媽這麼擔心……嗚嗚！"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"그런 곳……? 내가 어딜 갔다는 건데……?","JPN":"あんなところ……？　僕がどこに行ってたって……？","ENG":"A place like that...? Where was I at...?","TWN":"那種地方……？我是去哪裡……？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MOM_NPC_GAMECIRCLE_NULL","text":{"KOREA":"너? 지금 무슨 소리를 하는 거니!?","JPN":"ちょっと。何言ってるの！？","ENG":"What? What are you talking about...?","TWN":"你？你在說什麼！？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"……벌써 거의 한달이 다 되어가는군요.","JPN":"……もうひと月くらい経ちますかね。","ENG":"...It’s been almost a month.","TWN":"……你已經昏迷了一個月。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"코믹 페스티벌이라고 했던가?","JPN":"コミックフェスティバルといったかな？","ENG":"The Comic Festival, was it?","TWN":"那個是叫動漫展嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"아무튼 여의도의 한 행사에서 큰 사고가 일어났어요.","JPN":"とにかく、セリカ町のあるイベント会場で大きな事故がありました。","ENG":"There was a big accident at a convention center in Yeouido.","TWN":"總之在汝夷島舉辦的一場活動中發生意外，"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"……그리고 철수 군은 그 사고에 휘말렸고요.","JPN":"……そして、ジロウ君はその事故に巻き込まれたんです。","ENG":"...Which you were in, Chulsoo.","TWN":"……而你也捲入那場意外之中。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"어때요? 여기서 뭔가 기억나는 게 있나요?","JPN":"どうですか？　ここまでで何か思い出したことはありますか？","ENG":"How do you feel? Can you remember anything related to the incident?","TWN":"怎麼樣？你有想起什麼嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"……아니요.","JPN":"……いいえ。","ENG":"...I don't think so.","TWN":"……我什麼都想不起來。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"그렇군요. 어머님 말씀으로는 철수 군이 등교 거부 중이었다고 하던데.","JPN":"そうですか。お母さんの話では、ジロウ君は不登校中だったそうですね。","ENG":"I see. I hear from your mother that you’ve been refusing to go to school.","TWN":"是嗎？媽媽說你拒絕上學，"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"그런데 최근에는 꽤 자주 집밖에 나가게 됐다고 하더군요. 철수 군은 어딜 갔던 거죠?","JPN":"でも、最近はしょっちゅう外に出ていたと。ジロウ君はどこに行っていたのですか？","ENG":"But then, I also hear that you have been out often recently. Do you remember where you were?","TWN":"而且還很常出門，你記得你是去哪裡嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"……모르겠어요.","JPN":"……わかりません。","ENG":"...I don’t know.","TWN":"……我不記得。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MOM_NPC_GAMECIRCLE_NULL","text":{"KOREA":"철수야! 똑바로 생각해 봐! 최근에 자주 외출했잖아! 외박도 하고!","JPN":"ジロウ！　ちゃんと考えてみなさい！　最近よく出かけてたでしょ？　外泊もして！","ENG":"Come on, Chulsoo! Think! You’ve been out a lot! You even spent the night outside!","TWN":"哲洙！你再仔細想想！你最近不是老往外跑嗎？甚至還在外面過夜！"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MOM_NPC_GAMECIRCLE_NULL","text":{"KOREA":"아무래도 <color=#ffd34c>친구</color>가 생겼던 것 같았는데…… 혹시 기억나?","JPN":"誰か<color=#ffd34c>友達</color>ができたみたいだったけど……覚えてない？","ENG":"I assume you’ve made yourself some <color=#ffd34c>friends</color>... Does that bring back any memories?","TWN":"應該是有交到什麼<color=#ffd34c>朋友</color>吧……你記得嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"……몰라.","JPN":"……わかんない。","ENG":"...No.","TWN":"……不記得。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"엄마가 무슨 말하는지…… 모르겠어.","JPN":"お母さんが何言ってるのか……わからないよ。","ENG":"I don’t know what you’re talking about, Mom...","TWN":"媽你在說什麼……我完全聽不懂。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MOM_NPC_GAMECIRCLE_NULL","text":{"KOREA":"그, 그럼…… 그래! 너 최근에 그림 열심히 그렸잖니?","JPN":"じゃ、じゃあ……そうだ！　あんた、最近一生懸命絵を描いていたでしょ？","ENG":"T-then... Yes, that’s it! You were working hard on your drawings!","TWN":"那…那……還有！你最近不是很認真在畫畫嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MOM_NPC_GAMECIRCLE_NULL","text":{"KOREA":"니가 그린 그림이야! 이래도 아무것도 생각 안나? 네가 제일 좋아하는 캐릭터잖아!","JPN":"あんたが描いた絵だよ！　これでも何も思い出さない？　あんたが一番好きなキャラクターじゃない！","ENG":"This is the one you drew! You still can’t think of anything? It’s your favorite character!","TWN":"這是你畫的畫！還是什麼都想不起來？這不是你最喜歡的角色嗎！"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L44_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"몰라, 이젠…… 별로 관심 없어…….","JPN":"わかんない、もう……別に興味ない……","ENG":"I don’t know anymore... I’m not that interested.","TWN":"我不記得…而且…我現在不喜歡了……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"피곤해…… 잘래…….","JPN":"疲れた……寝る……","ENG":"I feel tired... I’m going to sleep more...","TWN":"我好累……我要睡一下……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"어머니, 이제 그만합시다. 애도 좀 쉬어야죠.","JPN":"お母さん、もうやめましょう。この子も少し休まないと。","ENG":"We should stop here. He needs more rest.","TWN":"哲洙媽媽，我看就先這樣吧，孩子也需要休息一下。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"다행히 최근에 있었던 일만 기억하지 못하는 것 같아요.","JPN":"幸い、最近の出来事だけ忘れているようです。","ENG":"Thankfully, it’s only his recent memory that’s been damaged.","TWN":"幸好他似乎只有想不起來最近發生過的事，"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"이 정도면 일상생활에는 크게 지장이 없을겁니다.","JPN":"このくらいなら、日常生活に支障はないはずですよ。","ENG":"I presume he wouldn’t have any problems dealing with daily activities.","TWN":"對他的日常生活應該影響不大。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"몸에 큰 후유증이나 이상이 있는 것도 아니니까, 문득 기억이 돌아올 수도 있고요.","JPN":"身体に大きな後遺症や異常もありませんから、ふと記憶が戻ってくるかもしれませんし。","ENG":"He doesn’t have any severe injuries either. His memories might come back someday.","TWN":"而且也不會留下什麼問題或後遺症，或許哪天他會突然想起來也說不定，"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOCTOR_EXTRA_NULL_NULL","text":{"KOREA":"자자, 그러니까 너무 걱정 마시고…….","JPN":"さあ、ですからあまり心配なさらずに……","ENG":"So, no need to get too discouraged...","TWN":"放輕鬆點，哲洙媽媽就別太擔心……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHEOLSU_NPC_GAMECIRCLE_CHILD","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHEOLSU_NPC_GAMECIRCLE_CHILD","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOM_NPC_GAMECIRCLE_NULL","text":{"KOREA":"흑, 흐윽. 그렇지만…… 왜 하필 내 아들이……! 내 아들이!!","JPN":"うっ、ううっ。でも……なんで私の息子が……！　私の息子が！！","ENG":"*Sob* *Sob* B-but... my son...! My son...!","TWN":"嗚，嗚嗚，為什麼……為什麼偏偏是我的兒子……！為什麼！！"},"stage":{"bg":"CORRIDOR_05","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_05","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그런 기가…… 우리 때문에…….","JPN":"そうか……ウチらのせいで……","ENG":"I see... It’s all because of us...","TWN":"原來如此……都是我們害的……"},"stage":{"bg":"CORRIDOR_05","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"미안하데이. 박스…… 아니 철수야.","JPN":"ごめんな。ダンボール……いや、ジロウ。","ENG":"I’m sorry, Box... I mean, Chulsoo.","TWN":"對不起，紙箱……不，哲洙。"},"stage":{"bg":"CORRIDOR_05","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};